  return <div className='home-app'>

    <div >
    <CustomCard content={
      <CollapsedText
        title={"Game"}
        description={"First game"}
        content={
          <Button
            buttonLabel="game"
            onClickNavigate="/game"
          />
        }
      />
    } />
